# Price table — update when provider changes pricing
# Claude pricing as of mid-2025 (USD per 1M tokens)
MODEL_PRICING = {
    "claude-haiku-4-5": {"input": 0.80, "output": 4.00},
    "claude-sonnet-4-5": {"input": 3.00, "output": 15.00},
    "claude-opus-4-5":  {"input": 15.00, "output": 75.00},
}

def compute_llm_cost(model: str, input_tokens: int, output_tokens: int) -> float:
    """Return cost in USD for one LLM call."""
    pricing = MODEL_PRICING.get(model)
    if pricing is None:
        raise ValueError(f"Unknown model: {model}")
    input_cost  = (input_tokens  / 1_000_000) * pricing["input"]
    output_cost = (output_tokens / 1_000_000) * pricing["output"]
    return round(input_cost + output_cost, 8)


# Tool API cost table — maintained manually
TOOL_COST_USD = {
    "web_search":    0.003,   # per call
    "code_executor": 0.010,   # per run
    "news_api":      0.0005,  # per call
}

def compute_tool_cost(tool_name: str) -> float:
    return TOOL_COST_USD.get(tool_name, 0.0)

import functools
import uuid

def track_cost(budget_usd: float = 1.0, agent_type: str = "default"):
    """Decorator that wraps an agent function with a CostLedger and enforces a budget."""
    def decorator(func):
        @functools.wraps(func)
        def wrapper(user_id: str, *args, **kwargs):
            session_id = str(uuid.uuid4())
            ledger = CostLedger(
                session_id=session_id,
                user_id=user_id,
                agent_type=agent_type,
                budget_usd=budget_usd,
            )
            try:
                result = func(user_id, *args, ledger=ledger, **kwargs)
                return result
            except BudgetExceededError:
                raise
            finally:
                emit_task_cost_metrics(ledger)
                print(f"[COST] session={session_id} total=${ledger.total_cost_usd:.4f} "
                      f"llm_calls={ledger.llm_calls} tool_calls={ledger.tool_calls}")
        return wrapper
    return decorator


@track_cost(budget_usd=0.25, agent_type="research")
def run_research_agent(user_id: str, query: str, ledger: CostLedger) -> str:
    agent = CostTrackingAgent(ledger.session_id, user_id, budget_usd=0.25)
    return agent.run(query)
